kubectl logs es-cluster-0 -n elasticsearch --tail=30 2>&1 | python3 -c "
import sys, json
for line in sys.stdin:
    line = line.strip()
    try:
        d = json.loads(line)
        lvl = d.get('log.level','')
        msg = d.get('message','')
        if lvl in ('ERROR','WARN','INFO') or 'error' in msg.lower():
            print(f'[{lvl}] {msg[:200]}')
    except:
        print(line[:200])
" 2>&1 | head -40
